const applyBuilder = (builder: VBIBuilder) => {
  builder.dimensions.add('product_type', node => {
    node.setAlias('商品类型')
  })
  const dimensionId = builder.dimensions.find(node => node.getField() === 'product_type')?.getId()
  if (dimensionId) {
    builder.dimensions.update(dimensionId, node => {
      node.setAlias('产品类型')
    })
  }
}
